import{_ as a,c as i,o as s,a1 as t}from"./chunks/framework.TuIRSVI8.js";const p=JSON.parse('{"title":"mac version","description":"","frontmatter":{"title":"mac version","pageClass":"mac-theme"},"headers":[],"relativePath":"versions/mac/index.md","filePath":"versions/mac/index.md","lastUpdated":1765874455000}'),o={name:"versions/mac/index.md"};function r(l,e,n,c,h,d){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="mac-macos-notes" tabindex="-1">mac (macOS) Notes <a class="header-anchor" href="#mac-macos-notes" aria-label="Permalink to &quot;mac (macOS) Notes&quot;">​</a></h1><p>Base docs apply from <strong>main</strong>. Differences to know:</p><h2 id="install-prereqs" tabindex="-1">Install / Prereqs <a class="header-anchor" href="#install-prereqs" aria-label="Permalink to &quot;Install / Prereqs&quot;">​</a></h2><ul><li>chezmoi auto-installs in the one-liner; no extra prereqs.</li><li>Homebrew stays; we don’t replace it—tools can come from brew or mise.</li><li>OneDrive detection on mac: <code>~/Library/CloudStorage/OneDrive-Personal</code> or <code>~/OneDrive</code> (native client). Rclone not required on mac.</li></ul><h2 id="paths-secrets" tabindex="-1">Paths &amp; secrets <a class="header-anchor" href="#paths-secrets" aria-label="Permalink to &quot;Paths &amp; secrets&quot;">​</a></h2><ul><li>1Password with TouchID: <code>op</code> CLI + browser integration; no secrets in git.</li><li>mac-specific templates live under <code>private_dot_config</code> and <code>dot_config</code> with <code>darwin</code> gates.</li></ul><h2 id="platforms-branches" tabindex="-1">Platforms / branches <a class="header-anchor" href="#platforms-branches" aria-label="Permalink to &quot;Platforms / branches&quot;">​</a></h2><ul><li>If you’re on macOS, you can use <strong>main</strong> or <strong>mac</strong>; both work. <strong>mac</strong> is this page of callouts; code is shared with main.</li><li>Steam Deck/Bazzite? Use <strong>bazzite</strong> instead.</li></ul><h2 id="quick-start-mac" tabindex="-1">Quick start (mac) <a class="header-anchor" href="#quick-start-mac" aria-label="Permalink to &quot;Quick start (mac)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsLS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get.chezmoi.io)&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aristoddle/beppe-system-bootstrap</span></span></code></pre></div><h2 id="deltas-vs-main" tabindex="-1">Deltas vs main <a class="header-anchor" href="#deltas-vs-main" aria-label="Permalink to &quot;Deltas vs main&quot;">​</a></h2><ul><li>Native OneDrive path (no rclone needed).</li><li>TouchID/1Password flow for <code>op</code> CLI; Homebrew coexists with mise.</li><li>mac-specific shell paths/completions; keychain-friendly ssh-agent.</li></ul><h2 id="things-that-differ-on-mac" tabindex="-1">Things that differ on mac <a class="header-anchor" href="#things-that-differ-on-mac" aria-label="Permalink to &quot;Things that differ on mac&quot;">​</a></h2><ul><li>Package manager: Homebrew + mise coexist (don’t delete Homebrew).</li><li>Shell hooks: mac paths for completions, keychain/ssh-agent integration.</li><li>Cloud storage: native OneDrive path; iCloud is ignored by default.</li></ul><h2 id="health-troubleshooting" tabindex="-1">Health / troubleshooting <a class="header-anchor" href="#health-troubleshooting" aria-label="Permalink to &quot;Health / troubleshooting&quot;">​</a></h2><ul><li>Run <code>dotfiles doctor</code> after apply.</li><li>If completions lag: <code>rm -rf ~/.cache/zsh/p10k; exec zsh</code>.</li><li>If brew and mise disagree on a tool: prefer mise for dev runtimes; keep brew for system/GUI.</li></ul>',16)])])}const u=a(o,[["render",r]]);export{p as __pageData,u as default};
